def trimmed_mean(nums):
    if not nums:
        return None
    nums = sorted(nums)
    if len(nums) <= 1:
        return sum(nums) / len(nums)
    min_occurrences, max_occurrences = nums.count(min(nums)), nums.count(max(nums))
    if min_occurrences > 1 or max_occurrences > 1:
        return (sum(nums[1:-1]) + nums[len(nums) // 2]) / len(nums[1:-1])
    if min_occurrences == 1:
        return (sum(nums[1:]) + sum(nums[:-1])) / (len(nums) - 1)
    return (sum(nums[1:]) + nums[0]) / len(nums)
